        "duration_sec": 4.0,
    },
]

GENERIC_MOVES = {"cinematic", "dramatic", "beautiful", "epic", ""}

def audit_shot_list(shots):
    suggestions = []
    for i, shot in enumerate(shots, start=1):
        move = shot.get("camera_move", "")
        dur = shot.get("duration_sec", 0.0)
        desc = shot.get("description", "")

        if move.strip().lower() in GENERIC_MOVES:
            suggestions.append(
                f"shot {i}: '{move}' is not a camera move. "
                "Specify one (push-in / orbit / track / pan / tilt / static)."
            )
            continue

        if "dolly zoom" in move.lower() and dur < 3.0:
            suggestions.append(
                f"shot {i}: dolly zoom in {dur}s is too fast — needs >=3s to read."
            )
            continue

        if "orbit" in move.lower() and dur < 4.0:
            suggestions.append(
                f"shot {i}: orbit in {dur}s won't complete cleanly — needs >=4s."
            )
            continue

        if "push-in" in move.lower() and dur < 2.0:
            suggestions.append(
                f"shot {i}: push-in in {dur}s reads as a jump — needs >=2s for the slow read."
            )
            continue

        if len(desc) < 20:
            suggestions.append(
                f"shot {i}: description too short ({len(desc)} chars) — "
                "needs subject + action + framing detail."
            )
            continue

    return suggestions

for s in audit_shot_list(shots):
    print(s)

